{
  "sentences": [
    {
      "text": "請你走進來。",
      "pinyin": "Qǐng nǐ zǒu jìnlái.",
      "pinyin_numeric": "qing3 ni3 zou3 jin4lai2",
      "translation_en": "Please walk in.",
      "translation_ko": "안으로 걸어 들어오세요."
    },
    {
      "text": "他跑出去了。",
      "pinyin": "Tā pǎo chūqù le.",
      "pinyin_numeric": "ta1 pao3 chu1qu4 le0",
      "translation_en": "He ran out.",
      "translation_ko": "그가 밖으로 뛰어나갔어요."
    },
    {
      "text": "我們把書拿出來。",
      "pinyin": "Wǒmen bǎ shū ná chūlái.",
      "pinyin_numeric": "wo3men ba3 shu1 na2 chu1lai2",
      "translation_en": "We take the book out.",
      "translation_ko": "우리가 책을 꺼내요."
    },
    {
      "text": "貓跳下來了。",
      "pinyin": "Māo tiào xiàlái le.",
      "pinyin_numeric": "mao1 tiao4 xia4lai2 le0",
      "translation_en": "The cat jumped down.",
      "translation_ko": "고양이가 뛰어내렸어요."
    },
    {
      "text": "請你帶上去。",
      "pinyin": "Qǐng nǐ dài shàngqù.",
      "pinyin_numeric": "qing3 ni3 dai4 shang4qu4",
      "translation_en": "Please take it up.",
      "translation_ko": "위로 가져가 주세요."
    },
    {
      "text": "他走進來了。",
      "pinyin": "Tā zǒu jìnlái le.",
      "pinyin_numeric": "ta1 zou3 jin4lai2 le0",
      "translation_en": "He walked in.",
      "translation_ko": "그가 걸어 들어왔어요."
    },
    {
      "text": "我們把東西放進去。",
      "pinyin": "Wǒmen bǎ dōngxi fàng jìnqù.",
      "pinyin_numeric": "wo3men ba3 dong1xi fang4 jin4qu4",
      "translation_en": "We put the things in.",
      "translation_ko": "우리가 물건을 안에 넣어요."
    },
    {
      "text": "鳥飛出去了。",
      "pinyin": "Niǎo fēi chūqù le.",
      "pinyin_numeric": "niao3 fei1 chu1qu4 le0",
      "translation_en": "The bird flew out.",
      "translation_ko": "새가 밖으로 날아갔어요."
    },
    {
      "text": "請你爬上來。",
      "pinyin": "Qǐng nǐ pá shànglái.",
      "pinyin_numeric": "qing3 ni3 pa2 shang4lai2",
      "translation_en": "Please climb up.",
      "translation_ko": "위로 기어 올라오세요."
    },
    {
      "text": "他跑下去了。",
      "pinyin": "Tā pǎo xiàqù le.",
      "pinyin_numeric": "ta1 pao3 xia4qu4 le0",
      "translation_en": "He ran down.",
      "translation_ko": "그가 뛰어내려갔어요."
    }
  ]
}
